   174  // hostRewrites calculates the changes necessary to attach the host endpoint
   175  // programs to different interfaces.
   176  func hostRewrites(cfg *datapath.LocalNodeConfiguration, ep datapath.Endpoint, ifName string) (map[string]uint64, map[string]string, error) {
   177          opts := ELFVariableSubstitutions(ep)
   178          strings := ELFMapSubstitutions(ep)
   179
   180          iface, err := safenetlink.LinkByName(ifName)
   181          if err != nil {
   182                  return nil, nil, err
   183          }
   184
   185          // The THIS_INTERFACE_MAC value is specific to each attachment interface.
   186          mac := mac.MAC(iface.Attrs().HardwareAddr)
   187          if mac == nil {
   188                  // L2-less device
   189                  mac = make([]byte, 6)
   190                  opts["ETH_HLEN"] = uint64(0)
   191          }
   192          opts["THIS_INTERFACE_MAC_1"] = uint64(sliceToBe32(mac[0:4]))
   193          opts["THIS_INTERFACE_MAC_2"] = uint64(sliceToBe16(mac[4:6]))
   194
   195          ifIndex := uint32(iface.Attrs().Index)
   196
   197          if !option.Config.EnableHostLegacyRouting {
   198                  opts["SECCTX_FROM_IPCACHE"] = uint64(secctxFromIpcacheEnabled)
   199          } else {
   200                  opts["SECCTX_FROM_IPCACHE"] = uint64(secctxFromIpcacheDisabled)
   201          }
   202
   203          // Overwrite the host endpoint ifindex assigned in ELFVariableSubstitutions
   204          // with the external device's.
   205          opts["interface_ifindex"] = uint64(ifIndex)
   206
   207          if option.Config.EnableBPFMasquerade && ifName != defaults.SecondHostDevice {
   208                  ipv4, ipv6 := bpfMasqAddrs(ifName, cfg)
   209
   210                  if option.Config.EnableIPv4Masquerade && ipv4.IsValid() {
   211                          opts["IPV4_MASQUERADE"] = uint64(byteorder.NetIPv4ToHost32(ipv4.AsSlice()))
   212                  }
   213                  if option.Config.EnableIPv6Masquerade && ipv6.IsValid() {
   214                          ipv6Bytes := ipv6.AsSlice()
   215                          opts["IPV6_MASQUERADE_1"] = sliceToBe64(ipv6Bytes[0:8])
   216                          opts["IPV6_MASQUERADE_2"] = sliceToBe64(ipv6Bytes[8:16])
   217                  }
   218          }
   219
   220          callsMapHostDevice := bpf.LocalMapName(callsmap.HostMapName, templateLxcID)
   221          strings[callsMapHostDevice] = bpf.LocalMapName(callsmap.NetdevMapName, uint16(ifIndex))
   222
   223          return opts, strings, nil
   224  }
