   586  func replaceOverlayDatapath(ctx context.Context, cArgs []string, device netlink.Link) error {
   587          if err := compileOverlay(ctx, cArgs); err != nil {
   588                  return fmt.Errorf("compiling overlay program: %w", err)
   589          }
   590
   591          spec, err := bpf.LoadCollectionSpec(overlayObj)
   592          if err != nil {
   593                  return fmt.Errorf("loading eBPF ELF %s: %w", overlayObj, err)
   594          }
   595
   596          var obj overlayObjects
   597          commit, err := bpf.LoadAndAssign(&obj, spec, &bpf.CollectionOptions{
   598                  Constants: map[string]uint64{
   599                          "interface_ifindex": uint64(device.Attrs().Index),
   600                  },
   601                  CollectionOptions: ebpf.CollectionOptions{
   602                          Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
   603                  },
   604          })
   605          if err != nil {
   606                  return err
   607          }
   608          defer obj.Close()
   609
   610          linkDir := bpffsDeviceLinksDir(bpf.CiliumPath(), device)
   611          if err := attachSKBProgram(device, obj.FromOverlay, symbolFromOverlay,
   612                  linkDir, netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
   613                  return fmt.Errorf("interface %s ingress: %w", device, err)
   614          }
   615          if err := attachSKBProgram(device, obj.ToOverlay, symbolToOverlay,
   616                  linkDir, netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
   617                  return fmt.Errorf("interface %s egress: %w", device, err)
   618          }
   619
   620          if err := commit(); err != nil {
   621                  return fmt.Errorf("committing bpf pins: %w", err)
   622          }
   623
   624          return nil
   625  }
