   627  func replaceWireguardDatapath(ctx context.Context, cArgs []string, device netlink.Link) (err error) {
   628          if err := compileWireguard(ctx, cArgs); err != nil {
   629                  return fmt.Errorf("compiling wireguard program: %w", err)
   630          }
   631
   632          spec, err := bpf.LoadCollectionSpec(wireguardObj)
   633          if err != nil {
   634                  return fmt.Errorf("loading eBPF ELF %s: %w", wireguardObj, err)
   635          }
   636
   637          var obj wireguardObjects
   638          commit, err := bpf.LoadAndAssign(&obj, spec, &bpf.CollectionOptions{
   639                  Constants: map[string]uint64{
   640                          "interface_ifindex": uint64(device.Attrs().Index),
   641                  },
   642                  CollectionOptions: ebpf.CollectionOptions{
   643                          Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
   644                  },
   645          })
   646          if err != nil {
   647                  return err
   648          }
   649          defer obj.Close()
   650
   651          linkDir := bpffsDeviceLinksDir(bpf.CiliumPath(), device)
   652          // Attach/detach cil_to_wireguard to/from egress.
   653          if option.Config.NeedEgressOnWireGuardDevice() {
   654                  if err := attachSKBProgram(device, obj.ToWireguard, symbolToWireguard,
   655                          linkDir, netlink.HANDLE_MIN_EGRESS, option.Config.EnableTCX); err != nil {
   656                          return fmt.Errorf("interface %s egress: %w", device, err)
   657                  }
   658          } else {
   659                  if err := detachSKBProgram(device, symbolToWireguard,
   660                          linkDir, netlink.HANDLE_MIN_EGRESS); err != nil {
   661                          log.WithField("device", device).Error(err)
   662                  }
   663          }
   664          // Selectively detach cil_from_netdev from ingress.
   665          if !option.Config.NeedBPFHostOnWireGuardDevice() {
   666                  if err := detachSKBProgram(device, symbolFromHostNetdevEp,
   667                          linkDir, netlink.HANDLE_MIN_INGRESS); err != nil {
   668                          log.WithField("device", wgTypes.IfaceName).Error(err)
   669                  }
   670                  // When downgrading from v1.18 we must also detach cil_from_wireguard:
   671                  // - if the hook is still needed, then cil_from_wireguard is removed in
   672                  //   attachNetworkDevices() as soon as cil_from_netdev is inserted;
   673                  // - otherwise we handle here its removal.
   674                  if err := detachSKBProgram(device, symbolFromWireguard,
   675                          linkDir, netlink.HANDLE_MIN_INGRESS); err != nil {
   676                          log.WithField("device", device).Error(err)
   677                  }
   678                  // Cleanup also calls map from v1.18 after downgrade.
   679                  cleanCallsMaps(fmt.Sprintf("cilium_calls_wireguard_%d", device.Attrs().Index))
   680          }
   681          if err := commit(); err != nil {
   682                  return fmt.Errorf("committing bpf pins: %w", err)
   683          }
   684          return nil
   685  }
