    97  func addENIRules(sysSettings []tables.Sysctl) ([]tables.Sysctl, error) {
    98          // AWS ENI mode requires symmetric routing, see
    99          // iptables.addCiliumENIRules().
   100          // The default AWS daemonset installs the following rules that are used
   101          // for NodePort traffic between nodes:
   102          //
   103          // # sysctl -w net.ipv4.conf.eth0.rp_filter=2
   104          // # iptables -t mangle -A PREROUTING -i eth0 -m comment --comment "AWS, primary ENI" -m addrtype --dst-type LOCAL --limit-iface-in -j CONNMARK --set-xmark 0x80/0x80
   105          // # iptables -t mangle -A PREROUTING -i eni+ -m comment --comment "AWS, primary ENI" -j CONNMARK --restore-mark --nfmask 0x80 --ctmask 0x80
   106          // # ip rule add fwmark 0x80/0x80 lookup main
   107          //
   108          // It marks packets coming from another node through eth0, and restores
   109          // the mark on the return path to force a lookup into the main routing
   110          // table. Without these rules, the "ip rules" set by the cilium-cni
   111          // plugin tell the host to lookup into the table related to the VPC for
   112          // which the CIDR used by the endpoint has been configured.
   113          //
   114          // We want to reproduce equivalent rules to ensure correct routing.
   115          if !option.Config.EnableIPv4 {
   116                  return sysSettings, nil
   117          }
   118
   119          iface, err := route.NodeDeviceWithDefaultRoute(option.Config.EnableIPv4, option.Config.EnableIPv6)
   120          if err != nil {
   121                  return nil, fmt.Errorf("failed to find interface with default route: %w", err)
   122          }
   123
   124          retSettings := append(sysSettings, tables.Sysctl{
   125                  Name:      []string{"net", "ipv4", "conf", iface.Attrs().Name, "rp_filter"},
   126                  Val:       "2",
   127                  IgnoreErr: false,
   128          })
   129          if err := route.ReplaceRule(route.Rule{
   130                  Priority: linux_defaults.RulePriorityNodeport,
   131                  Mark:     linux_defaults.MarkMultinodeNodeport,
   132                  Mask:     linux_defaults.MaskMultinodeNodeport,
   133                  Table:    route.MainTable,
   134                  Protocol: linux_defaults.RTProto,
   135          }); err != nil {
   136                  return nil, fmt.Errorf("unable to install ip rule for ENI multi-node NodePort: %w", err)
   137          }
   138
   139          return retSettings, nil
   140  }
