   167  // cleanCallsMaps is used to remove any pinned map matching mapNamePattern from bpf.TCGlobalsPath().
   168  func cleanCallsMaps(mapNamePattern string) error {
   169          matches, err := filepath.Glob(filepath.Join(bpf.TCGlobalsPath(), mapNamePattern))
   170          if err != nil {
   171                  return fmt.Errorf("failed to list maps with mapNamePattern %s: %w", mapNamePattern, err)
