   181  // reinitializeIPSec is used to recompile and load encryption network programs.
   182  func (l *loader) reinitializeIPSec() error {
   183          // We need to take care not to load bpf_network and bpf_host onto the same
   184          // device. If devices are required, we load bpf_host and hence don't need
   185          // the code below, specific to EncryptInterface. Specifically, we will load
   186          // bpf_host code in reloadHostDatapath onto the physical devices as selected
   187          // by configuration.
   188          if !option.Config.EnableIPSec || option.Config.AreDevicesRequired() {
   189                  return nil
   190          }
   191
   192          l.ipsecMu.Lock()
   193          defer l.ipsecMu.Unlock()
   194
   195          interfaces := option.Config.EncryptInterface
   196          if option.Config.IPAM == ipamOption.IPAMENI {
   197                  // IPAMENI mode supports multiple network facing interfaces that
   198                  // will all need Encrypt logic applied in order to decrypt any
   199                  // received encrypted packets. This logic will attach to all
   200                  // !veth devices.
   201                  interfaces = nil
   202                  links, err := safenetlink.LinkList()
   203                  if err != nil {
   204                          return err
   205                  }
   206                  for _, link := range links {
   207                          isVirtual, err := ethtool.IsVirtualDriver(link.Attrs().Name)
   208                          if err == nil && !isVirtual {
   209                                  interfaces = append(interfaces, link.Attrs().Name)
   210                          }
   211                  }
   212                  option.Config.EncryptInterface = interfaces
   213
   214          }
   215
   216          // No interfaces is valid in tunnel disabled case
   217          if len(interfaces) == 0 {
   218                  return nil
   219          }
   220
   221          spec, err := bpf.LoadCollectionSpec(networkObj)
   222          if err != nil {
   223                  return fmt.Errorf("loading eBPF ELF %s: %w", networkObj, err)
   224          }
   225
   226          var obj networkObjects
   227          commit, err := bpf.LoadAndAssign(&obj, spec, &bpf.CollectionOptions{
   228                  CollectionOptions: ebpf.CollectionOptions{
   229                          Maps: ebpf.MapOptions{PinPath: bpf.TCGlobalsPath()},
   230                  },
   231          })
   232          if err != nil {
   233                  return err
   234          }
   235          defer obj.Close()
   236
   237          var errs error
   238          for _, iface := range interfaces {
   239                  device, err := safenetlink.LinkByName(iface)
   240                  if err != nil {
   241                          errs = errors.Join(errs, fmt.Errorf("retrieving device %s: %w", iface, err))
   242                          continue
   243                  }
   244
   245                  if err := attachSKBProgram(device, obj.FromNetwork, symbolFromNetwork,
   246                          bpffsDeviceLinksDir(bpf.CiliumPath(), device), netlink.HANDLE_MIN_INGRESS, option.Config.EnableTCX); err != nil {
   247
   248                          // Collect errors, keep attaching to other interfaces.
   249                          errs = errors.Join(errs, fmt.Errorf("interface %s: %w", iface, err))
   250                          continue
   251                  }
   252
   253                  log.WithField(logfields.Interface, iface).Info("Encryption network program (re)loaded")
   254          }
   255
   256          if errs != nil {
   257                  return fmt.Errorf("failed to load encryption program: %w", errs)
   258          }
   259
   260          if err := commit(); err != nil {
   261                  return fmt.Errorf("committing bpf pins: %w", err)
   262          }
   263
   264          return nil
   265  }
