   267  func reinitializeOverlay(ctx context.Context, tunnelConfig tunnel.Config) error {
   268          // tunnelConfig.Protocol() can be one of tunnel.[Disabled, VXLAN, Geneve]
   269          // if it is disabled, the overlay network programs don't have to be (re)initialized
   270          if tunnelConfig.Protocol() == tunnel.Disabled {
   271                  cleanCallsMaps("cilium_calls_overlay*")
   272                  return nil
   273          }
   274
   275          iface := tunnelConfig.DeviceName()
   276          link, err := safenetlink.LinkByName(iface)
   277          if err != nil {
   278                  return fmt.Errorf("failed to retrieve link for interface %s: %w", iface, err)
   279          }
   280
   281          // gather compile options for bpf_overlay.c
   282          opts := []string{
   283                  fmt.Sprintf("-DSECLABEL=%d", identity.ReservedIdentityWorld),
   284                  fmt.Sprintf("-DTHIS_INTERFACE_MAC={.addr=%s}", mac.CArrayString(link.Attrs().HardwareAddr)),
   285                  fmt.Sprintf("-DCALLS_MAP=cilium_calls_overlay_%d", identity.ReservedIdentityWorld),
   286          }
   287          if option.Config.EnableNodePort {
   288                  opts = append(opts, "-DDISABLE_LOOPBACK_LB")
   289          }
   290          if option.Config.IsDualStack() {
   291                  opts = append(opts, fmt.Sprintf("-DSECLABEL_IPV4=%d", identity.ReservedIdentityWorldIPv4))
   292                  opts = append(opts, fmt.Sprintf("-DSECLABEL_IPV6=%d", identity.ReservedIdentityWorldIPv6))
   293          } else {
   294                  opts = append(opts, fmt.Sprintf("-DSECLABEL_IPV4=%d", identity.ReservedIdentityWorld))
   295                  opts = append(opts, fmt.Sprintf("-DSECLABEL_IPV6=%d", identity.ReservedIdentityWorld))
   296          }
   297
   298          if err := replaceOverlayDatapath(ctx, opts, link); err != nil {
   299                  return fmt.Errorf("failed to load overlay programs: %w", err)
   300          }
   301
   302          return nil
   303  }
