   328  func reinitializeXDPLocked(ctx context.Context, extraCArgs []string, devices []string, xdpConfig xdp.Config) error {
   329          maybeUnloadObsoleteXDPPrograms(devices, xdpConfig.Mode(), bpf.CiliumPath())
   330          if xdpConfig.Disabled() {
   331                  return nil
   332          }
   333          for _, dev := range devices {
   334                  // When WG & encrypt-node are on, the devices include cilium_wg0 to attach bpf_host
   335                  // so that NodePort's rev-{S,D}NAT translations happens for a reply from the remote node.
   336                  // So We need to exclude cilium_wg0 not to attach the XDP program when XDP acceleration
   337                  // is enabled, otherwise we will get "operation not supported" error.
   338                  if dev == wgTypes.IfaceName {
   339                          continue
   340                  }
   341
   342                  if err := compileAndLoadXDPProg(ctx, dev, xdpConfig.Mode(), extraCArgs); err != nil {
   343                          if option.Config.NodePortAcceleration == option.XDPModeBestEffort {
   344                                  log.WithError(err).WithField(logfields.Device, dev).Info("Failed to attach XDP program, ignoring due to best-effort mode")
   345                          } else {
   346                                  return fmt.Errorf("attaching XDP program to interface %s: %w", dev, err)
   347                          }
   348                  }
   349          }
   350
   351          // Clean up the legacy cilium_calls_xdp path.
   352          // TODO:  Remove in Cilium 1.17.
   353          os.Remove(filepath.Join(bpf.TCGlobalsPath(), "cilium_calls_xdp"))
   354
   355          return nil
   356  }
