        e.runlock()

        // DistillPolicy converts a SelectorPolicy in to an EndpointPolicy
        result.endpointPolicy = selectorPolicy.DistillPolicy(e, desiredRedirects)

        datapathRegenCtxt.policyResult = result
        return nil
